	const deletionOrder: { line: number; char: number }[] = [];
	for (let l = lines.length - 1; l >= 0; l--) {
		for (let c = lines[l].length - 1; c >= 1; c--) {
			deletionOrder.push({ line: l, char: c });
		}
	}

	const v2DeletionOrder: { line: number; char: number }[] = [
		{ line: 2, char: 4 },
		{ line: 0, char: 3 },
		{ line: 1, char: 2 },
