	];

	function getCharVisible(lineIndex: number, charIndex: number): boolean {
		if (charIndex === 0) return true;
		if (prefersReducedMotion) return deleteProgress < 0.5;

		const charsToDelete = Math.floor(deleteProgress * totalDeletableChars);
		const effectiveDeleted = Math.max(0, charsToDelete - hoverRevealCount);
		const order = isV2 ? v2DeletionOrder : deletionOrder;
		const deleted = order.slice(0, effectiveDeleted);
		return !deleted.some(d => d.line === lineIndex && d.char === charIndex);
	}

	function clearHoverTimer() {
		if (hoverTimer) {
			clearInterval(hoverTimer);
			hoverTimer = null;
		}
	}

	function handleLogoEnter() {
		if (prefersReducedMotion || deleteProgress === 0) return;
		clearHoverTimer();
		const target = Math.floor(deleteProgress * totalDeletableChars);
		hoverTimer = setInterval(() => {
			if (hoverRevealCount >= target) {
				clearHoverTimer();
				return;
			}
			hoverRevealCount++;
		}, 18);
	}

	function handleLogoLeave() {
		clearHoverTimer();
		hoverTimer = setInterval(() => {
			if (hoverRevealCount <= 0) {
				clearHoverTimer();
				return;
			}
			hoverRevealCount--;
		}, 12);
	}

	let isAboutPage = $derived(page.url.pathname.includes('/about'));
	let isDetailPage = $derived(page.url.pathname.startsWith('/projects/'));
	let v2Qs = $derived(isV2 && baseHref === '/' ? '?v2' : '');

	function scrollToTop() {
		setActiveView('selected');
		mobileMenuOpen = false;
		if (isAboutPage) {
			goto(baseHref + v2Qs);
		} else {
			window.scrollTo({ top: 0, behavior: 'instant' });
		}
	}

	function scrollToIndex() {
		setActiveView('index');
		mobileMenuOpen = false;
		if (isAboutPage) {
			goto(baseHref + v2Qs + '#index');
		} else {
			const el = document.getElementById('index');
			if (el) el.scrollIntoView({ behavior: 'instant' });
		}
	}

	function handleAboutMobile() {
		mobileMenuOpen = false;
	}

	$effect(() => {
		if (!browser) return;
		prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
	});

	$effect(() => {
		if (!browser) return;

		function onScroll() {
			if (isDetailPage) {
				deleteProgress = 1;
				return;
			}
			const vh = window.innerHeight;
			const deleteStart = vh * 0.3;
			const deleteEnd = vh * 1.0;
			const prev = deleteProgress;
			deleteProgress = Math.max(0, Math.min(1, (window.scrollY - deleteStart) / (deleteEnd - deleteStart)));
			if (deleteProgress === 0 && prev > 0) {
				hoverRevealCount = 0;
				clearHoverTimer();
			}
		}

		window.addEventListener('scroll', onScroll, { passive: true });
		onScroll();
		return () => window.removeEventListener('scroll', onScroll);
	});
</script>

<nav class="nav-bar" class:in-index={getActiveView() === 'index'} class:on-about={isAboutPage} class:on-detail={isDetailPage}>
	<a href={baseHref + v2Qs} class="nav-logo" aria-label="Studio Linse Hoogervorst"
		onmouseenter={handleLogoEnter}
		onmouseleave={handleLogoLeave}
	>
		{#if isV2}
			<svg class="logo-svg v2-logo" viewBox="0 0 178 74" fill="currentColor" xmlns="http://www.w3.org/2000/svg">
				{#each v2LetterPaths as lp}
					<path d={lp.d} class:letter-dissolving={!getCharVisible(lp.line, lp.char)} />
				{/each}
			</svg>
		{:else}
			<svg class="logo-svg" width="147" height="73" viewBox="0 0 147 73" fill="none" xmlns="http://www.w3.org/2000/svg">
				{#each letterPaths as lp}
					<path d={lp.d} fill="currentColor" class:letter-hidden={!getCharVisible(lp.line, lp.char)} />
				{/each}
			</svg>
		{/if}
	</a>

	<div class="nav-right-desktop">
		<button class="nav-link" class:active={!isAboutPage && getActiveView() === 'selected'} onclick={scrollToTop}>Selected,</button>
		<button class="nav-link" class:active={!isAboutPage && getActiveView() === 'index'} onclick={scrollToIndex}>Index,</button>
		<a href={baseHref === '/' ? '/studio/about' + v2Qs : baseHref + '/about'} class="nav-link" class:active={isAboutPage}>About</a>
	</div>

	<button class="nav-menu-btn" onclick={() => mobileMenuOpen = !mobileMenuOpen}>
		{mobileMenuOpen ? 'Close' : 'Menu'}
	</button>
</nav>

{#if mobileMenuOpen}
	<div class="mobile-menu" class:in-index={getActiveView() === 'index'} class:on-detail={isDetailPage}>
		<button class="mobile-menu-link" class:active={!isAboutPage && getActiveView() === 'selected'} onclick={scrollToTop}>Selected</button>
		<button class="mobile-menu-link" class:active={!isAboutPage && getActiveView() === 'index'} onclick={scrollToIndex}>Index</button>
		<a href={baseHref === '/' ? '/studio/about' + v2Qs : baseHref + '/about'} class="mobile-menu-link" class:active={isAboutPage} onclick={handleAboutMobile}>About</a>
	</div>
{/if}

<style>
	.nav-bar {
		position: fixed;
		top: 0;
		left: 0;
		width: 100%;
		display: flex;
		justify-content: space-between;
		align-items: flex-start;
		padding: 8px;
		z-index: 20;
		mix-blend-mode: exclusion;
		color: #fff;
		pointer-events: none;
	}

	.nav-bar.on-about {
		mix-blend-mode: normal;
		color: var(--color-primary);
	}

	.nav-logo {
		pointer-events: auto;
		display: block;
		text-decoration: none;
	}

	.logo-svg {
		display: block;
		height: 72px;
		width: auto;
	}

	.v2-logo {
		height: 72px;
		width: auto;
	}

	.v2-logo path {
		transition: opacity 0.4s ease, transform 0.4s ease;
		transform-box: fill-box;
		transform-origin: center;
	}

	.letter-dissolving {
		opacity: 0;
		transform: scale(0.8);
	}

	.letter-hidden {
		visibility: hidden;
	}

	.nav-right-desktop {
		display: flex;
		align-items: baseline;
		gap: 4px;
		font-family: var(--font-meta);
		font-weight: 500;
		font-size: 14px;
		line-height: 17px;
		white-space: nowrap;
	}

	.nav-menu-btn {
		display: none;
	}

	.nav-link {
		color: inherit;
		text-decoration: none;
		pointer-events: auto;
		cursor: pointer;
		background: none;
		border: none;
		font: inherit;
		padding: 0;
	}

	.nav-link.active {
		font-style: italic;
	}

	.nav-link:hover {
		opacity: 0.6;
	}

	.mobile-menu {
		display: none;
	}

	@media (max-width: 768px) {
		.nav-bar {
			mix-blend-mode: normal;
			color: #fff;
		}

		.nav-bar.in-index {
			mix-blend-mode: exclusion;
			color: #fff;
		}

		.nav-bar.on-detail {
			mix-blend-mode: exclusion;
			color: #fff;
		}

		.nav-bar.on-about {
			mix-blend-mode: normal;
			color: var(--color-primary);
		}

		.nav-right-desktop {
			display: none;
		}

		.nav-menu-btn {
			display: block;
			pointer-events: auto;
			cursor: pointer;
			background: none;
			border: none;
			color: inherit;
			font-family: var(--font-meta);
			font-weight: 500;
			font-size: 14px;
			line-height: 17px;
			padding: 0;
		}

		.mobile-menu {
			display: flex;
			flex-direction: column;
			align-items: flex-end;
			gap: 8px;
			position: fixed;
			top: 32px;
			right: 8px;
			z-index: 20;
			color: #fff;
			mix-blend-mode: normal;
			font-family: var(--font-meta);
			font-weight: 500;
			font-size: 14px;
			line-height: 17px;
		}

		.mobile-menu.in-index {
			mix-blend-mode: exclusion;
			color: #fff;
		}

		.mobile-menu.on-detail {
			mix-blend-mode: exclusion;
			color: #fff;
		}

		.mobile-menu-link {
			color: inherit;
			text-decoration: none;
			cursor: pointer;
			background: none;
			border: none;
			font: inherit;
			padding: 0;
		}

		.mobile-menu-link.active {
			font-style: italic;
		}
	}
</style>
